CODE_EXAMPLE:
// TDD cycle: test first, then code
// Step 1 - RED: failing test
@Test public void pop_returnsLastPushedItem() {
    Stack<Integer> stack = new Stack<>();
    stack.push(1);
    assertEquals(1, (int) stack.pop());
}

// Step 2 - GREEN: minimal production code to pass
public class Stack<T> {
    private List<T> items = new ArrayList<>();
    public void push(T item)  { items.add(item); }
    public T    pop()         { return items.remove(items.size() - 1); }
}

// Step 3 - REFACTOR: clean up while tests remain green

UNIT_TEST_EXAMPLE:
@Test
public void push_andPop_maintainsLIFOOrder() {
    Stack<Integer> stack = new Stack<>();
    stack.push(1); stack.push(2); stack.push(3);
    assertEquals(3, (int) stack.pop());
    assertEquals(2, (int) stack.pop());
    assertEquals(1, (int) stack.pop());
}

@Test
public void pop_throwsOnEmptyStack() {
    Stack<Integer> stack = new Stack<>();
    assertThrows(IndexOutOfBoundsException.class, stack::pop);
}
